const deal = $('Deal Contract Sent Webhook').first().json;
const config = $('Get Config').first().json;
const body = deal.body && typeof deal.body === 'object' ? deal.body : deal;
const props = body.properties || body;

const valueFrom = (...values) => {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim()) {
      return String(value).trim();
    }
  }
  return '';
};

const money = (value) => {
  if (value === undefined || value === null || value === '') return 0;
  const normalized = Number(String(value).replace(/[^0-9.-]/g, ''));
  return Number.isFinite(normalized) ? normalized : 0;
};

const titleCase = (value) => value ? value.charAt(0).toUpperCase() + value.slice(1) : '';

const addressParts = [
  valueFrom(props.address, props.street, props.street_address, props.company_address),
  valueFrom(props.city, props.company_city),
  valueFrom(props.state, props.state_region, props.company_state),
  valueFrom(props.zip, props.zip_code, props.postal_code, props.company_zip),
  valueFrom(props.country, props.company_country)
].filter(Boolean);

const tierKey = valueFrom(props.tier).toLowerCase() || 'starter';
const tierInfo = (config.tiers && (config.tiers[tierKey] || config.tiers.starter)) || {
  name: titleCase(tierKey) || 'Starter',
  monthlyPrice: 0,
  setupFee: 0
};

const rawPainSources = [
  valueFrom(props.deal_pain_points),
  valueFrom(props.painPoints),
  valueFrom(props.pain_point_summary)
].filter(Boolean);

const uniquePainSources = [...new Set(rawPainSources)];
const painPoints = uniquePainSources.join('\n\n');
const contactFirstName = valueFrom(props.contact_firstname, props.firstName, props.firstname);
const contactLastName = valueFrom(props.contact_lastname, props.lastName, props.lastname);
const contactName = [contactFirstName, contactLastName].filter(Boolean).join(' ');

const companyName = valueFrom(
  props.company,
  props.company_name,
  props.business_name,
  props.dealname,
  props.name
);
const tierMonthly = money(tierInfo.monthlyPrice);
const upfrontDue = money(tierInfo.setupFee);
const tierAmount = money(props.amount) || upfrontDue;
const remainingTierBalance = Math.max(tierAmount - upfrontDue, 0);
const launchBalance = remainingTierBalance + tierMonthly;

return [{
  json: {
    clientName: valueFrom(props.dealname, props.name, props.company, props.business_name, props.company_name),
    company: companyName,
    companyName,
    industry: valueFrom(props.industry),
    painPoints,
    painPointSummary: valueFrom(props.pain_point_summary, props.painPoints),
    rawPainPoints: valueFrom(props.deal_pain_points, painPoints),
    dealValue: tierAmount,
    tierAmount,
    tier: tierKey,
    tierLabel: tierInfo.name || titleCase(tierKey) || 'Starter',
    tierMonthly,
    upfrontDue,
    launchBalance,
    dealId: valueFrom(body.id, deal.id, body.dealId, deal.dealId),
    contactEmail: valueFrom(props.contact_email, props.email),
    contactPhone: valueFrom(props.contact_phone, props.phone, props.mobilephone),
    contactFirstName,
    contactName: contactName || contactFirstName,
    address: addressParts.join(', '),
    driveFolderId: valueFrom(props.client_drive_folder_id),
    config
  }
}];

const d = $('Extract Deal Data').first().json;
return [{
  json: {
    message: `Contract Generation skipped: no client_drive_folder_id on deal for "${d.clientName}". Set the property or complete onboarding so the client Drive folder exists.`,
    priority: 'warning'
  }
}];

const d = $('Extract Deal Data').first().json;
const scopeContext = [d.rawPainPoints, d.painPointSummary].filter(Boolean).join('
') || d.painPoints || '(None provided)';

return [{
  json: {
    systemPrompt: 'You are drafting Exhibit A (Statement of Work) for a Master Services Agreement for IntraWeb Technologies LLC, an implementation and automation consultancy. Output ONLY clean semantic HTML for the exhibit body: no markdown, no backticks, no DOCTYPE, no html/head/body tags. Use h2, h3, p, ul, ol, li, strong. This is an operational scope description, not legal language—no warranties, governing law, or liability caps. Do not invent facts not supported by the payload.',
    userPrompt: `Write Exhibit A — Statement of Work for this engagement.

Client: ${d.clientName}
Company: ${d.company}
Industry: ${d.industry || 'Not provided'}
Tier: ${d.tierLabel}
Project / tier amount: $${d.tierAmount || 0}
Monthly recurring (if applicable): $${d.tierMonthly || 0}
Upfront / setup portion: $${d.upfrontDue || 0}

Context from discovery (use for scope only):
"""
${scopeContext}
"""

Return sections:
1. Objectives
2. Deliverables and workstreams (bullet lists)
3. Client responsibilities (assumptions, access, approvals)
4. Out of scope (explicit)
5. Change requests (brief process)

Keep it concise and implementation-ready.`,
    maxTokens: 3500
  }
}];

const raw = $('Call Claude API').first().json;
const text = (raw.content && raw.content[0] && raw.content[0].text) ? raw.content[0].text : '';
const d = $('Extract Deal Data').first().json;
return [{ json: { data: { text }, html: text, fileName: `IntraWeb — ${d.clientName} — Master Services Agreement.pdf` } }];

const claudeResult = $('Parse Claude Response').first().json;
const d = $('Extract Deal Data').first().json;
const owner = (d.config && d.config.owner) || {};
const companyName = owner.companyName || 'IntraWeb Technologies LLC';
const ownerEmail = owner.email || '';
const ownerPhone = owner.phone || '';
const ownerName = owner.name || 'Authorized Representative';
const clientLegalName = d.company || d.clientName || 'Client';
const effectiveDate = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
const exhibitBody = (claudeResult.data ? claudeResult.data.text : claudeResult.html || '').trim() || '<p>Exhibit A could not be generated.</p>';

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;')
  .replace(/'/g, '&#39;');

const formatCurrency = (value) => {
  const numeric = Number(value || 0);
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(Number.isFinite(numeric) ? numeric : 0);
};

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Master Services Agreement — ${escapeHtml(clientLegalName)}</title>
  <link href="https://fonts.googleapis.com/css2?family=Source+Serif+4:ital,wght@0,400;0,600;0,700;1,400&family=Manrope:wght@400;600;700&display=swap" rel="stylesheet">
  <style>
    @page { size: Letter; margin: 0.65in; }
    * { box-sizing: border-box; }
    body { margin: 0; padding: 0; font-family: 'Source Serif 4', Georgia, serif; font-size: 11.5px; line-height: 1.55; color: #1a1f2e; }
    h1 { font-family: 'Manrope', Arial, sans-serif; font-size: 22px; margin: 0 0 8px; letter-spacing: -0.02em; }
    .sub { font-family: 'Manrope', Arial, sans-serif; font-size: 11px; color: #5b6472; margin-bottom: 20px; }
    h2 { font-family: 'Manrope', Arial, sans-serif; font-size: 13px; text-transform: uppercase; letter-spacing: 0.08em; color: #374151; margin: 22px 0 10px; border-bottom: 1px solid #e5e7eb; padding-bottom: 6px; }
    h3 { font-size: 12.5px; margin: 14px 0 8px; }
    p { margin: 0 0 10px; }
    ul, ol { margin: 0 0 10px 18px; padding: 0; }
    table.fees { width: 100%; border-collapse: collapse; margin: 10px 0 16px; font-family: 'Manrope', Arial, sans-serif; font-size: 11px; }
    table.fees td { padding: 8px 10px; border: 1px solid #e5e7eb; vertical-align: top; }
    table.fees td:last-child { text-align: right; font-weight: 700; width: 28%; }
    .parties { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin: 14px 0; }
    .party { border: 1px solid #e5e7eb; border-radius: 8px; padding: 12px 14px; background: #fafbfc; }
    .party .label { font-family: 'Manrope', Arial, sans-serif; font-size: 9px; text-transform: uppercase; letter-spacing: 0.1em; color: #6b7280; margin-bottom: 6px; }
    .exhibit { border: 1px solid #d1d5db; border-radius: 10px; padding: 16px 18px; margin: 16px 0 20px; background: #fff; }
    .exhibit h2:first-child, .exhibit h3:first-child { margin-top: 0; }
    .sig { margin-top: 28px; display: grid; grid-template-columns: 1fr 1fr; gap: 24px; break-inside: avoid; }
    .sig-box { border-top: 1px solid #111827; padding-top: 8px; min-height: 64px; font-family: 'Manrope', Arial, sans-serif; font-size: 10px; }
    .notice { font-family: 'Manrope', Arial, sans-serif; font-size: 9.5px; color: #6b7280; margin-top: 20px; padding: 10px 12px; background: #f9fafb; border: 1px dashed #d1d5db; border-radius: 8px; line-height: 1.45; }
  </style>
</head>
<body>
  <h1>Master Services Agreement</h1>
  <p class="sub">Effective date: ${escapeHtml(effectiveDate)} &nbsp;|&nbsp; ${escapeHtml(companyName)}</p>

  <h2>Parties</h2>
  <div class="parties">
    <div class="party">
      <div class="label">Client</div>
      <p><strong>${escapeHtml(clientLegalName)}</strong><br/>Attn: ${escapeHtml(d.contactName || d.contactFirstName || '—')}<br/>${d.address ? escapeHtml(d.address) + '<br/>' : ''}${d.contactEmail ? escapeHtml(d.contactEmail) : ''}</p>
    </div>
    <div class="party">
      <div class="label">Provider</div>
      <p><strong>${escapeHtml(companyName)}</strong><br/>${ownerEmail ? escapeHtml(ownerEmail) : ''}${ownerPhone ? '<br/>' + escapeHtml(ownerPhone) : ''}</p>
    </div>
  </div>

  <h2>1. Services</h2>
  <p>Provider will perform the professional services described in <strong>Exhibit A</strong> (Statement of Work), which is incorporated into this Agreement. Exhibit A may be updated by written agreement of the parties (including email).</p>

  <h2>2. Fees and payment</h2>
  <p>Fees are based on the commercial terms selected for this engagement unless otherwise agreed in writing.</p>
  <table class="fees">
    <tr><td>Tier / package amount</td><td>${escapeHtml(formatCurrency(d.tierAmount))}</td></tr>
    <tr><td>Estimated upfront / setup</td><td>${escapeHtml(formatCurrency(d.upfrontDue))}</td></tr>
    <tr><td>Monthly recurring (if applicable)</td><td>${escapeHtml(formatCurrency(d.tierMonthly))}</td></tr>
    <tr><td>Launch / initial payment (estimate)</td><td>${escapeHtml(formatCurrency(d.launchBalance))}</td></tr>
  </table>
  <p>Invoices are due per the payment instructions on the invoice unless a different schedule is agreed in writing. Late payments may incur suspension of work until accounts are current.</p>

  <h2>3. Term</h2>
  <p>This Agreement begins on the Effective Date and continues until the services in Exhibit A are completed and fees for completed work are paid, unless terminated earlier under Section 4.</p>

  <h2>4. Termination</h2>
  <p>Either party may terminate for material breach if the other party fails to cure within fifteen (15) days of written notice. Client remains responsible for fees for work performed through the termination date.</p>

  <h2>5. Confidentiality</h2>
  <p>Each party agrees to protect the other’s non-public business information using reasonable care and to use it only for this engagement.</p>

  <h2>6. Intellectual property</h2>
  <p>Client retains ownership of its pre-existing materials. Deliverables created specifically for Client are assigned to Client upon full payment, excluding Provider tools, templates, and general know-how.</p>

  <h2>7. Limitation of liability</h2>
  <p>To the maximum extent permitted by law, neither party is liable for indirect or consequential damages. Provider’s total liability under this Agreement for any claim is limited to the fees paid by Client to Provider in the three (3) months preceding the claim.</p>

  <h2>8. Independent contractor</h2>
  <p>Provider is an independent contractor. This Agreement does not create a partnership or employment relationship.</p>

  <h2>9. Notices</h2>
  <p>Notices may be sent to the emails listed above or to such other addresses as the parties designate in writing.</p>

  <h2>10. Exhibit A — Statement of Work</h2>
  <div class="exhibit exhibit-body">${exhibitBody}</div>

  <h2>11. Signatures</h2>
  <p>By signing below, the parties agree to this Agreement including Exhibit A.</p>
  <div class="sig">
    <div class="sig-box"><strong>${escapeHtml(clientLegalName)}</strong><br/><br/>Name: ___________________________<br/>Title: ___________________________<br/>Date: ___________________________</div>
    <div class="sig-box"><strong>${escapeHtml(companyName)}</strong><br/><br/>Name: ${escapeHtml(ownerName)}<br/>Title: Authorized Representative<br/>Date: ___________________________</div>
  </div>

  <p class="notice"><strong>Important:</strong> This document is a business template for internal use. It is not legal advice. Have qualified counsel review and customize before execution. Electronic signature and filing are your team’s responsibility after internal approval in the master sheet.</p>
</body>
</html>`;

return [{ json: { html, fileName: `IntraWeb — ${d.clientName} — Master Services Agreement.pdf` } }];

const item = $input.first();
const fileName = $('Prep Contract PDF').first().json.fileName || 'contract.pdf';
return [{ json: { fileName }, binary: item.binary ? { ...item.binary } : {} }];

const d = $('Extract Deal Data').first().json;
const uploadOut = $('Upload to Drive').first();
const fileId = uploadOut?.json?.id ?? uploadOut?.json?.data?.id ?? '';
const driveLink = fileId ? 'https://drive.google.com/file/d/' + fileId : '';
return [{
  json: {
    message: driveLink
      ? `Contract PDF ready for ${d.clientName} — approve in **Contracts** tab then client email sends: ${driveLink}`
      : `Contract PDF ready for ${d.clientName} — set **Contracts** Status to Approved to send. (Drive link unavailable.)`,
    priority: 'info'
  }
}];

const d = $('Extract Deal Data').first().json;
const uploadOut = $('Upload to Drive').first();
const fileId = uploadOut?.json?.id ?? uploadOut?.json?.data?.id ?? '';
const driveLink = fileId ? 'https://drive.google.com/file/d/' + fileId : '';
return [{
  json: {
    to: d.contactEmail,
    subject: `Your IntraWeb agreement — ${d.clientName}`,
    html: `<p>Hi ${d.contactFirstName || 'there'},</p><p>Your Master Services Agreement is ready for review.</p>${driveLink ? `<p><a href="${driveLink}">Open the agreement PDF in Google Drive</a></p>` : ''}<p>Please review the scope and commercial terms. If everything looks right, reply to this email and we will coordinate signature (e-signature or wet sign) on the final copy.</p><p>If you need changes, reply with edits and we will send an updated version.</p><p>— ${d.config?.owner?.name || 'John'}<br/>${d.config?.owner?.companyName || 'IntraWeb Technologies'}</p>`,
    workflowName: 'SYS 03 — Contract Generation'
  }
}];

return [{
  json: {
    workflowName: 'SYS 03 — Contract Generation',
    contactName: $('Extract Deal Data').first().json.clientName,
    phone: '',
    eventType: 'contract_pdf_sent',
    status: 'success',
    notes: `Deal value: $${$('Extract Deal Data').first().json.dealValue}`
  }
}];
